import { Graph, Selection, Snapline, History, Keyboard, Clipboard } from '@antv/x6';

const graph = new Graph({
  container: 'container',
  background: { color: '#F2F7FA' },
  grid: { visible: true },
  connecting: {
    allowBlank: false,
    snap: { radius: 20 },
    createEdge() {
      return this.createEdge({
        attrs: { line: { stroke: '#8f8f8f', strokeWidth: 1, targetMarker: 'classic' } },
      });
    },
  },
});

graph.use(new Selection({ enabled: true, multiple: true, rubberband: true, showNodeSelectionBox: true }));
graph.use(new Snapline({ enabled: true }));
graph.use(new History({ enabled: true }));
graph.use(new Clipboard({ enabled: true }));
graph.use(new Keyboard({ enabled: true, global: true }));

graph.bindKey('ctrl+z', () => { graph.undo(); return false; });
graph.bindKey('ctrl+shift+z', () => { graph.redo(); return false; });
graph.bindKey('ctrl+c', () => { const cells = graph.getSelectedCells(); if (cells.length) graph.copy(cells); return false; });
graph.bindKey('ctrl+v', () => { if (!graph.isClipboardEmpty()) { const cells = graph.paste({ offset: 32 }); graph.cleanSelection(); graph.select(cells); } return false; });
graph.bindKey('delete', () => { const cells = graph.getSelectedCells(); if (cells.length) graph.removeCells(cells); return false; });

graph.addNode({
  x: 60, y: 60, width: 100, height: 40, label: 'Start',
  attrs: { body: { stroke: '#52c41a', strokeWidth: 2, fill: '#f6ffed', rx: 6, ry: 6 } },
  ports: {
    groups: { out: { position: 'bottom', attrs: { circle: { magnet: true, stroke: '#8f8f8f', r: 5 } } } },
    items: [{ id: 'out1', group: 'out' }],
  },
});

graph.addNode({
  x: 60, y: 200, width: 100, height: 40, label: 'End',
  attrs: { body: { stroke: '#f5222d', strokeWidth: 2, fill: '#fff1f0', rx: 6, ry: 6 } },
