import { Graph } from '@antv/x6';

const graph = new Graph({
  container: 'container',
  background: { color: '#F2F7FA' },
  connecting: {
    router: 'orth',
    connector: 'rounded',
  },
});

// 添加中心节点
const centerNode = graph.addNode({
  id: 'center',
  shape: 'circle',
  x: 200,
  y: 120,
  width: 70,
  height: 70,
  label: 'Center',
  attrs: {
    body: { stroke: '#8f8f8f', strokeWidth: 1, fill: '#fff' },
    label: { fontSize: 12 },
  },
});

// 添加周围的节点并连接到中心节点
const nodes = [];
const nodePositions = [
  { x: 200, y: 20 },    // 上
  { x: 320, y: 120 },   // 右
  { x: 200, y: 220 },   // 下
  { x: 80, y: 120 },    // 左
];

for (let i = 0; i < 4; i++) {
  const node = graph.addNode({
    id: `node-${i}`,
    shape: 'rect',
    x: nodePositions[i].x,
    y: nodePositions[i].y,
    width: 80,
    height: 40,
    label: `N${i+1}`,
    attrs: {
      body: { stroke: '#8f8f8f', strokeWidth: 1, fill: '#fff', rx: 6, ry: 6 },
      label: { fontSize: 12 },
    },
  });

  graph.addEdge({
    source: 'center',
    target: `node-${i}`,
    attrs: {
      line: { stroke: '#8f8f8f', strokeWidth: 1 },
    },
  });

  nodes.push(node);
}

// 高亮相邻节点的函数
function highlightNeighbors(node) {
  // 重置所有节点样式
  graph.getNodes().forEach(n => {
    n.attr('body/fill', '#fff');
    n.attr('body/stroke', '#8f8f8f');
    n.attr('body/strokeWidth', 1);
  });

  // 获取相邻节点
  const neighbors = graph.getNeighbors(node);

  // 高亮当前节点
  node.attr('body/fill', '#1890ff');
  node.attr('body/stroke', '#1890ff');
  node.attr('body/strokeWidth', 2);

  // 高亮相邻节点
  neighbors.forEach(neighbor => {
    neighbor.attr('body/fill', '#bae7ff');
    neighbor.attr('body/stroke', '#1890ff');
    neighbor.attr('body/strokeWidth', 2);
  });
}

// 点击节点时高亮其相邻节点
graph.on('node:click', ({ node }) => {
  highlightNeighbors(node);
});

// 初始高亮中心节点的相邻节点
highlightNeighbors(centerNode);

graph.centerContent();

