// 注册自定义 HTML 节点
Shape.HTML.register({
  shape: 'data-process-node',
  effect: ['data'],
  html(node) {
    const data = node.getData();
    const div = document.createElement('div');

    // 设置容器样式
    div.style.cssText = `
      width: 100%;
      height: 100%;
      background: #ffffff;
      border: 1px solid #8f8f8f;
      border-radius: 6px;
      font-family: sans-serif;
      overflow: hidden;
      box-sizing: border-box;
    `;

    // 创建标题区域
    const header = document.createElement('div');
    header.style.cssText = `
      padding: 8px 12px;
      background: #f5f5f5;
      border-bottom: 1px solid #e0e0e0;
      font-weight: bold;
      font-size: 12px;
    `;
    header.textContent = data.processType || 'Data Process';

    // 创建内容区域
    const content = document.createElement('div');
    content.style.cssText = `
      padding: 10px 12px;
      font-size: 11px;
    `;

    // 显示配置参数
    const params = data.params || {};
    Object.keys(params).forEach(key => {
      const paramDiv = document.createElement('div');
      paramDiv.style.cssText = `
        margin-bottom: 4px;
        display: flex;
      `;

      const keySpan = document.createElement('span');
      keySpan.style.cssText = `
        font-weight: 500;
        margin-right: 6px;
        flex: 0 0 auto;
      `;
      keySpan.textContent = `${key}:`;

      const valueSpan = document.createElement('span');
      valueSpan.style.cssText = `
        flex: 1 1 auto;
        overflow: hidden;
        text-overflow: ellipsis;
      `;
      valueSpan.textContent = params[key];

      paramDiv.appendChild(keySpan);
      paramDiv.appendChild(valueSpan);
      content.appendChild(paramDiv);
    });

    div.appendChild(header);
    div.appendChild(content);

    return div;
  },
});

const graph = new Graph({
  container: 'container',
  background: { color: '#F2F7FA' },
  connecting: {
    router: 'orth',
    connector: 'rounded',
  },
});

// 创建带有输入输出端口的数据处理节点
const processDataNode = graph.addNode({
  shape: 'data-process-node',
  x: 100,
  y: 80,
  width: 200,
  height: 120,
  data: {
    processType: 'Data Transformation',
    params: {
      'inputFormat': 'JSON',
      'outputFormat': 'CSV',
      'compression': 'gzip'
    }
  },
  ports: {
    groups: {
      in: {
        position: 'left',
        attrs: {
          circle: {
            r: 4,
            magnet: true,
            stroke: '#8f8f8f',
            fill: '#fff'
          }
        }
      },
      out: {
        position: 'right',
        attrs: {
          circle: {
            r: 4,
            magnet: true,
            stroke: '#8f8f8f',
            fill: '#fff'
          }
        }
      }
    },
    items: [
      { id: 'port1', group: 'in' },
      { id: 'port2', group: 'out' }
    ]
  }
});

// 添加另一个节点用于连接
const targetNode = graph.addNode({
  shape: 'rect',
  x: 400,
  y: 100,
  width: 100,
  height: 40,
  label: 'Target',
  attrs: {
    body: { stroke: '#8f8f8f', strokeWidth: 1, fill: '#fff', rx: 6, ry: 6 },
  },
  ports: {
    groups: {
      in: {
        position: 'left',
        attrs: {
          circle: {
            r: 4,
            magnet: true,
            stroke: '#8f8f8f',
            fill: '#fff'
          }
        }
      }
    },
    items: [
      { id: 'port3', group: 'in' }
    ]
  }
});

// 添加连接线
graph.addEdge({
  source: { cell: processDataNode, port: 'port2' },
  target: { cell: targetNode, port: 'port3' },
  attrs: {
    line: {
      stroke: '#8f8f8f',
      strokeWidth: 1,
      targetMarker: 'classic'
    }
  }
});

graph.centerContent();

