  const colors = { online: '#52c41a', offline: '#ff4d4f', idle: '#faad14' };
  const color = colors[data.status] || '#d9d9d9';
  const div = document.createElement('div');
  div.style.cssText = 'width:100%;height:100%;display:flex;align-items:center;justify-content:center;border-radius:8px;border:2px solid ' + color + ';background:#fff;font-family:sans-serif;';
  div.innerHTML = `
