  y: 60,
  width: 200,
  height: 50,
  html: 'status-badge',
  data: { name: 'API Server', status: 'online' },
});

const node2 = graph.addNode({
  shape: 'html',
  x: 80,
  y: 140,
  width: 200,
  height: 50,
  html: 'status-badge',
  data: { name: 'Database', status: 'idle' },
});

const node3 = graph.addNode({
  shape: 'html',
  x: 80,
  y: 220,
  width: 200,
  height: 50,
