import { Graph, Shape } from '@antv/x6';

// 注册自定义 HTML 节点用于展示数据表
Shape.HTML.register({
  shape: 'erd-table',
  effect: ['data'],
  html(node) {
    const data = node.getData();
    const tableName = data.tableName || 'unnamed_table';
    const fields = data.fields || [];

    const wrap = document.createElement('div');
    wrap.style.cssText = `
      width: 100%;
      height: 100%;
      background: #fff;
      border: 1px solid #8f8f8f;
      border-radius: 6px;
      box-sizing: border-box;
      overflow: hidden;
      font-family: Arial, sans-serif;
    `;

    // 表名区域
    const header = document.createElement('div');
    header.style.cssText = `
      padding: 8px 12px;
      background: #e6f7ff;
      border-bottom: 1px solid #8f8f8f;
      font-weight: bold;
      text-align: center;
    `;
    header.textContent = tableName;
    wrap.appendChild(header);

    // 字段列表区域
    const body = document.createElement('div');
    body.style.cssText = `
      padding: 4px 0;
      max-height: 300px;
      overflow-y: auto;
    `;

    fields.forEach(field => {
      const row = document.createElement('div');
      row.style.cssText = `
        display: flex;
        padding: 4px 12px;
        border-bottom: 1px solid #f0f0f0;
        font-size: 12px;
      `;

      // 主键标识
      const pkCell = document.createElement('div');
      pkCell.style.cssText = `
        width: 20px;
        flex-shrink: 0;
        color: #ff4d4f;
        font-weight: bold;
      `;
      pkCell.textContent = field.isPrimary ? 'PK' : '';

      // 字段名
      const nameCell = document.createElement('div');
      nameCell.style.cssText = `
        flex: 1;
        overflow: hidden;
        text-overflow: ellipsis;
        white-space: nowrap;
      `;
      nameCell.textContent = field.name;

      // 类型
      const typeCell = document.createElement('div');
      typeCell.style.cssText = `
        width: 80px;
        flex-shrink: 0;
        color: #888;
        text-align: right;
      `;
      typeCell.textContent = field.type;

      row.appendChild(pkCell);
      row.appendChild(nameCell);
      row.appendChild(typeCell);
      body.appendChild(row);
    });

    wrap.appendChild(body);
    return wrap;
  },
});

// 初始化画布
