  container: container,
  background: { color: '#F2F7FA' },
  connecting: {
    router: 'orth',
    connector: {
      name: 'rounded',
      args: {
        radius: 8,
      },
    },
    allowBlank: false,
    allowLoop: false,
    allowNode: true,
    allowEdge: false,
    allowMulti: false,
    createEdge() {
      return this.createEdge({
        attrs: {
          line: {
            stroke: '#8f8f8f',
            strokeWidth: 1,
            targetMarker: 'classic',
          },
        },
      });
    },
  },
  interacting: {
    nodeMovable: true,
    edgeLabelMovable: false,
    edgeMovable: false,
    vertexMovable: false,
    vertexAddable: false,
  },
