const graph = new Graph({
  container: 'container',
  width: 800,
  height: 500,
  background: { color: '#F2F7FA' },
  grid: { visible: true, size: 10 },
  panning: { enabled: true, modifiers: 'shift' },
  mousewheel: { enabled: true, modifiers: 'ctrl' },
  connecting: {
    allowBlank: false,
    router: 'manhattan',
    connector: 'rounded',
    createEdge() {
      return this.createEdge({
        attrs: { line: { stroke: '#5F95FF', strokeWidth: 1, targetMarker: 'classic' } },
      });
    },
  },
});

graph.use(new Selection({ enabled: true, rubberband: true, multiple: true }));
graph.use(new Snapline({ enabled: true }));
graph.use(new History({ enabled: true }));
graph.use(new Keyboard({ enabled: true }));
graph.use(new Clipboard({ enabled: true }));

graph.bindKey('backspace', () => {
  const cells = graph.getSelectedCells();
  if (cells.length) graph.removeCells(cells);
});
graph.bindKey(['ctrl+z', 'meta+z'], () => graph.undo());
graph.bindKey(['ctrl+shift+z', 'meta+shift+z'], () => graph.redo());
graph.bindKey(['ctrl+c', 'meta+c'], () => graph.copy(graph.getSelectedCells()));
graph.bindKey(['ctrl+v', 'meta+v'], () => graph.paste());

