    },
    items: [{ group: 'top' }, { group: 'bottom' }, { group: 'left' }, { group: 'right' }],
  },
}, true);

const start = graph.addNode({ shape: 'flow-node', x: 320, y: 40, label: 'Start', attrs: { body: { fill: '#d9f7be', stroke: '#52c41a' } }, ports: { items: [{ group: 'bottom' }] } });
const process1 = graph.addNode({ shape: 'flow-node', x: 320, y: 140, label: 'Process Data' });
const decision = graph.addNode({ shape: 'polygon', x: 345, y: 250, width: 50, height: 50, attrs: { body: { fill: '#fffbe6', stroke: '#faad14', refPoints: '0,10 10,0 20,10 10,20' }, label: { text: 'OK?' } }, ports: { groups: { right: { position: 'right', attrs: { circle: { r: 4, magnet: true, stroke: '#faad14', fill: '#fff' } } }, bottom: { position: 'bottom', attrs: { circle: { r: 4, magnet: true, stroke: '#faad14', fill: '#fff' } } }, top: { position: 'top', attrs: { circle: { r: 4, magnet: true, stroke: '#faad14', fill: '#fff' } } } }, items: [{ group: 'top' }, { group: 'right' }, { group: 'bottom' }] } });
